    async def run_complete_benchmark(self, session_id: str = None) -> Dict[str, Any]:
        """Run the complete benchmark suite"""

        session_id = session_id or f"benchmark_{int(time.time())}"

        print(f"🚀 Starting Performance Benchmark Session: {session_id}")
        print("=" * 60)

        # Initialize session
        total_tests = len(self.benchmark_tests)
        estimated_duration = sum(test.time_limit_seconds for test in self.benchmark_tests)

        self.progress_tracker.start_session(session_id, estimated_duration, total_tests)

        # Setup phase
        self.progress_tracker.update_phase('setup', 1.0)
        print(self.progress_tracker.get_progress_display())

        # Run tests by tier
        tiers = [ResourceTier.LOW, ResourceTier.MEDIUM, ResourceTier.HIGH]

        for tier in tiers:
            tier_tests = [test for test in self.benchmark_tests if test.tier == tier]

            self.progress_tracker.update_phase(f'{tier.value}_tier_tests', 0.0)

            print(f"\n🎯 Running {tier.value.upper()} Resource Tier Tests")
            print("-" * 40)

            for i, test in enumerate(tier_tests):
                print(f"\n📋 Test: {test.name}")

                # Get learning engine recommendations
                learning_analysis = self.learning_engine.analyze_task_requirements(
                    test.input_prompt, test.tier
                )

                print(f"🧠 Learning Insights: {learning_analysis['recommended_approach']} "
                      f"(Confidence: {learning_analysis['confidence_level']:.1%})")

                # Run the test
                result = await self._run_single_test(test, learning_analysis)
                self.results.append(result)

                # Record learning outcome
                self.learning_engine.record_outcome(
                    test.input_prompt, test.tier, result.success, result.validation_details
                )

                # Update progress
                tier_progress = (i + 1) / len(tier_tests)
                self.progress_tracker.update_phase(f'{tier.value}_tier_tests', tier_progress)
                self.progress_tracker.update_test_completion(result.success)

                print(f"✅ Result: {'PASS' if result.success else 'FAIL'} "
                      f"({result.response_time:.2f}s)")

                print(self.progress_tracker.get_progress_display())

        # Analysis phase
        self.progress_tracker.update_phase('analysis', 0.5)
        analysis_results = self._analyze_results()
        self.progress_tracker.update_phase('analysis', 1.0)

        final_report = self._generate_final_report(session_id, analysis_results)

        print(f"\n📊 Benchmark Complete!")
        print(self.progress_tracker.get_progress_display())

        return final_report

    async def _run_single_test(self, test: BenchmarkTest, learning_analysis: Dict[str, Any]) -> BenchmarkResult:
        """Run a single benchmark test"""

        start_time = time.time()
        errors = []

        try:
            # Configure quality system for this tier
            if test.tier == ResourceTier.LOW:
                self.quality_system.set_mode('performance_first')
            elif test.tier == ResourceTier.MEDIUM:
                self.quality_system.set_mode('balanced')
            else:  # HIGH
                self.quality_system.set_mode('feature_rich')

            # Mock interactive instance for testing
            mock_interactive = self._create_mock_interactive(test.tier)

            # Process through quality system
            response, metadata = await self.quality_system.process_user_input(
                test.input_prompt,
                mock_interactive,
                context={
                    'resource_tier': test.tier.value,
                    'expected_type': test.expected_output_type,
                    'learning_analysis': learning_analysis
                }
            )

            response_time = time.time() - start_time

            # Validate the generated code
            validation_passed = False
            validation_details = {}

            if response and len(response) > 50:  # Reasonable code length
                test_type = self._determine_test_type(test.test_id)
                validation_passed, validation_details = self.validator.validate_python_code(
                    response, test_type
                )

            # Check success criteria
            success = self._check_success_criteria(test, response_time, response, validation_details)

            return BenchmarkResult(
                test_id=test.test_id,
                success=success,
                response_time=response_time,
                resource_tier_used=metadata.get('tier', 'unknown'),
                generated_output=response,
                validation_passed=validation_passed,
                validation_details=validation_details,
                learning_insights=learning_analysis,
                errors=errors,
                performance_metrics={
                    'response_time': response_time,
                    'code_length': len(response),
                    'confidence': learning_analysis.get('confidence_level', 0.0)
                }
            )

        except Exception as e:
            errors.append(str(e))

            return BenchmarkResult(
                test_id=test.test_id,
                success=False,
                response_time=time.time() - start_time,
                resource_tier_used='error',
                generated_output='',
                validation_passed=False,
                validation_details={'error': str(e)},
                learning_insights=learning_analysis,
                errors=errors,
                performance_metrics={}
            )

