    def _determine_test_type(self, test_id: str) -> str:
        """Determine test type for validation"""
        if 'hello_world' in test_id:
            return 'hello_world'
        elif 'calculator' in test_id or 'math' in test_id:
            return 'calculator'
        elif 'api' in test_id:
            return 'api'
        else:
            return 'general'

    def _check_success_criteria(self, test: BenchmarkTest, response_time: float,
                              response: str, validation_details: Dict[str, Any]) -> bool:
        """Check if test meets success criteria"""

        criteria = test.success_criteria

        # Check response time
        if response_time > criteria.get('max_time', float('inf')):
            return False

        # Check if code is executable
        if criteria.get('executable', False) and not validation_details.get('execution_successful', False):
            return False

        # Check for required elements
        if criteria.get('contains_function', False) and 'def ' not in response:
            return False

        if criteria.get('contains_class', False) and 'class ' not in response:
            return False

        return True

    def _analyze_results(self) -> Dict[str, Any]:
        """Analyze benchmark results"""

        if not self.results:
            return {}

        total_tests = len(self.results)
        successful_tests = sum(1 for r in self.results if r.success)

        # Performance by tier
        tier_analysis = {}
        for tier in ResourceTier:
            tier_results = [r for r in self.results if r.test_id.startswith(tier.value)]
            if tier_results:
                tier_analysis[tier.value] = {
                    'total': len(tier_results),
                    'successful': sum(1 for r in tier_results if r.success),
                    'avg_response_time': sum(r.response_time for r in tier_results) / len(tier_results),
                    'success_rate': sum(1 for r in tier_results if r.success) / len(tier_results)
                }

        return {
            'overall_stats': {
                'total_tests': total_tests,
                'successful_tests': successful_tests,
                'success_rate': successful_tests / total_tests,
                'avg_response_time': sum(r.response_time for r in self.results) / total_tests
            },
            'tier_analysis': tier_analysis,
            'learning_insights': {
                'patterns_discovered': len(self.learning_engine.success_patterns),
                'failure_patterns': len(self.learning_engine.failure_patterns)
            }
        }

    def _generate_final_report(self, session_id: str, analysis: Dict[str, Any]) -> Dict[str, Any]:
        """Generate comprehensive final report"""

        return {
            'session_id': session_id,
            'timestamp': time.time(),
            'benchmark_results': [asdict(result) for result in self.results],
            'performance_analysis': analysis,
            'quality_system_status': self.quality_system.get_system_status(),
            'learning_summary': {
                'total_patterns_learned': len(self.learning_engine.learning_logs),
                'success_patterns': len(self.learning_engine.success_patterns),
                'areas_for_improvement': self._identify_improvement_areas()
            },
            'presentation_summary': self._create_presentation_summary(analysis)
        }

    def _identify_improvement_areas(self) -> List[str]:
        """Identify areas for system improvement"""

        improvements = []

        failed_results = [r for r in self.results if not r.success]

        if failed_results:
            # Analyze failure patterns
            for result in failed_results:
                if result.response_time > 30:
                    improvements.append("Response time optimization needed for complex tasks")
                if not result.validation_passed:
                    improvements.append("Code generation accuracy needs improvement")

        return list(set(improvements))

    def _create_presentation_summary(self, analysis: Dict[str, Any]) -> Dict[str, Any]:
        """Create presentation-ready summary"""

        return {
            'key_achievements': [
                f"{analysis['overall_stats']['success_rate']:.1%} overall success rate",
                f"{analysis['overall_stats']['avg_response_time']:.2f}s average response time",
                f"{len(self.results)} comprehensive tests completed"
            ],
            'resource_tier_performance': analysis['tier_analysis'],
            'learning_highlights': [
                f"Discovered {analysis['learning_insights']['patterns_discovered']} successful patterns",
                f"Identified {analysis['learning_insights']['failure_patterns']} areas for improvement"
            ],
            'next_steps': self._identify_improvement_areas()
        }


